import json
import matplotlib.pyplot as plt

INPUT_FILE = "data/benchmark_results.json"
OUTPUT_IMAGE = "reports/benchmark_chart.png"

# Load the data generated by the benchmark script
with open(INPUT_FILE, "r") as f:
    data = json.load(f)

results = data["results"]
# Extract and sort qubits/latencies for the CPU
cpu_qubits = sorted([int(k) for k in results["cpu_qpp"].keys()])
cpu_times = [results["cpu_qpp"][str(q)] for q in cpu_qubits]

# Extract and sort qubits/latencies for the GPU
gpu_qubits = sorted([int(k) for k in results["gpu_nvidia"].keys()])
gpu_times = [results["gpu_nvidia"][str(q)] for q in gpu_qubits]

# Generate the performance graph
plt.figure(figsize=(9, 5))
plt.plot(cpu_qubits, cpu_times, 'r-o', label='Classical OpenMP CPU Engine')
plt.plot(gpu_qubits, gpu_times, 'g-s', label='NVIDIA GPU cuStateVec Acceleration')

plt.yscale('log')
plt.xlabel('Qubit Count Volume')
plt.ylabel('Execution Latency (Seconds)')
plt.title('Performance Scaling Analysis: Heterogeneous Quantum Emulation')
plt.grid(True, which="both", ls="--")
plt.legend()

# Save the artifact to the reports folder
plt.savefig(OUTPUT_IMAGE, dpi=300, bbox_inches='tight')
print(f"[SUCCESS] Chart saved to {OUTPUT_IMAGE}")
